using Microsoft.ML;
using TicketClassifier.Models;

namespace TicketClassifier.Services;

public class ModelTrainerService
{
    private readonly string _dataPath;
    private readonly string _modelPath;
    private readonly ILogger<ModelTrainerService> _logger;

    public ModelTrainerService(ILogger<ModelTrainerService> logger, IConfiguration configuration)
    {
        _logger = logger;
        _dataPath = configuration.GetValue<string>("ML:DataPath")
            ?? Path.Combine(AppContext.BaseDirectory, "Data", "tickets.csv");
        _modelPath = configuration.GetValue<string>("ML:ModelPath")
            ?? Path.Combine(AppContext.BaseDirectory, "Data", "model.zip");
    }

    public string ModelPath => _modelPath;

    public TrainingResult Train()
    {
        var mlContext = new MLContext(seed: 42);

        // Load data
        var data = mlContext.Data.LoadFromTextFile<TicketInput>(
            _dataPath, hasHeader: true, separatorChar: ',', allowQuoting: true);

        // Split into train/test sets
        var split = mlContext.Data.TrainTestSplit(data, testFraction: 0.2, seed: 42);

        // Build the pipeline
        var pipeline = mlContext.Transforms.Conversion
                .MapValueToKey("Label", nameof(TicketInput.Category))
            .Append(mlContext.Transforms.Text.FeaturizeText("SubjectFeatures", nameof(TicketInput.Subject)))
            .Append(mlContext.Transforms.Text.FeaturizeText("DescriptionFeatures", nameof(TicketInput.Description)))
            .Append(mlContext.Transforms.Concatenate("Features",
                "SubjectFeatures", "DescriptionFeatures", nameof(TicketInput.Priority)))
            .Append(mlContext.Transforms.NormalizeMinMax("Features"))
            .Append(mlContext.MulticlassClassification.Trainers.SdcaMaximumEntropy(
                labelColumnName: "Label", featureColumnName: "Features"))
            .Append(mlContext.Transforms.Conversion.MapKeyToValue("PredictedLabel"));

        _logger.LogInformation("Training model with {Path}...", _dataPath);
        var model = pipeline.Fit(split.TrainSet);

        // Evaluate on the test set
        var predictions = model.Transform(split.TestSet);
        var metrics = mlContext.MulticlassClassification.Evaluate(predictions, labelColumnName: "Label");

        _logger.LogInformation(
            "Macro Accuracy: {MacroAccuracy:F4}, Micro Accuracy: {MicroAccuracy:F4}, LogLoss: {LogLoss:F4}",
            metrics.MacroAccuracy, metrics.MicroAccuracy, metrics.LogLoss);

        // Build per-class metrics
        var perClassMetrics = metrics.PerClassLogLoss
            .Select((_, i) => new PerClassMetric
            {
                ClassName = i < metrics.PerClassLogLoss.Count ? $"Class {i}" : "Unknown",
                Precision = i < metrics.ConfusionMatrix.PerClassPrecision.Count
                    ? metrics.ConfusionMatrix.PerClassPrecision[i] : 0,
                Recall = i < metrics.ConfusionMatrix.PerClassRecall.Count
                    ? metrics.ConfusionMatrix.PerClassRecall[i] : 0,
                F1Score = CalculateF1(
                    i < metrics.ConfusionMatrix.PerClassPrecision.Count
                        ? metrics.ConfusionMatrix.PerClassPrecision[i] : 0,
                    i < metrics.ConfusionMatrix.PerClassRecall.Count
                        ? metrics.ConfusionMatrix.PerClassRecall[i] : 0),
            })
            .ToList();

        // Save the model
        Directory.CreateDirectory(Path.GetDirectoryName(_modelPath)!);
        mlContext.Model.Save(model, split.TrainSet.Schema, _modelPath);
        _logger.LogInformation("Model saved to {ModelPath}", _modelPath);

        return new TrainingResult
        {
            Message = "Model trained and saved successfully.",
            MacroAccuracy = metrics.MacroAccuracy,
            MicroAccuracy = metrics.MicroAccuracy,
            LogLoss = metrics.LogLoss,
            LogLossReduction = metrics.LogLossReduction,
            PerClassMetrics = perClassMetrics,
        };
    }

    private static double CalculateF1(double precision, double recall)
    {
        if (precision + recall == 0) return 0;
        return 2 * (precision * recall) / (precision + recall);
    }
}

using Microsoft.AspNetCore.Mvc;
using Microsoft.Extensions.ML;
using TicketClassifier.Models;
using TicketClassifier.Services;

namespace TicketClassifier.Controllers;

[ApiController]
[Route("api/[controller]")]
public class TicketsController : ControllerBase
{
    private readonly PredictionEnginePool<TicketInput, TicketPrediction> _predictionPool;
    private readonly ModelTrainerService _trainer;
    private readonly ILogger<TicketsController> _logger;

    public TicketsController(
        PredictionEnginePool<TicketInput, TicketPrediction> predictionPool,
        ModelTrainerService trainer,
        ILogger<TicketsController> logger)
    {
        _predictionPool = predictionPool;
        _trainer = trainer;
        _logger = logger;
    }

    /// <summary>Trains the model and returns evaluation metrics.</summary>
    [HttpPost("train")]
    public ActionResult<TrainingResult> Train()
    {
        var result = _trainer.Train();
        return Ok(result);
    }

    /// <summary>Predicts the category for a support ticket.</summary>
    [HttpPost("classify")]
    public ActionResult<TicketClassificationResult> Classify([FromBody] TicketRequest request)
    {
        if (string.IsNullOrWhiteSpace(request.Subject) && string.IsNullOrWhiteSpace(request.Description))
            return BadRequest("Subject or Description is required.");

        if (request.Priority < 1 || request.Priority > 3)
            return BadRequest("Priority must be between 1 and 3.");

        if (!System.IO.File.Exists(_trainer.ModelPath))
            return BadRequest("Model has not been trained yet. Call POST /api/tickets/train first.");

        var input = new TicketInput
        {
            Subject = request.Subject,
            Description = request.Description,
            Priority = request.Priority,
        };

        var prediction = _predictionPool.Predict(input);

        _logger.LogInformation(
            "Classified ticket as {Category} (Subject: {Subject})",
            prediction.Category, request.Subject);

        // Map scores to category names
        var labels = new[] { "Billing", "General", "Technical" };
        var confidence = new Dictionary<string, float>();
        for (var i = 0; i < Math.Min(labels.Length, prediction.Score.Length); i++)
        {
            confidence[labels[i]] = prediction.Score[i];
        }

        return Ok(new TicketClassificationResult
        {
            PredictedCategory = prediction.Category,
            Confidence = confidence,
        });
    }
}

